import { useT } from '../i18n/I18nContext'
import type { ConnectionState } from '../hooks/useTodoSyncHub'
import type { MessageKey } from '../i18n/messages'

interface Props {
  state: ConnectionState
}

function labelKey(state: ConnectionState): MessageKey {
  if (state === 'connected') return 'connection.connected'
  if (state === 'disconnected') return 'connection.disconnected'
  return 'connection.reconnecting'
}

function ConnectionIndicator({ state }: Props) {
  const { t } = useT()
  const label = t(labelKey(state))
  return (
    <span
      className="connection-dot"
      data-state={state}
      role="status"
      aria-label={label}
      title={label}
    />
  )
}

export default ConnectionIndicator

export interface TodoList {
  id: number
  name: string
  items: TodoListItem[]
}

export interface TodoListItem {
  id: number
  description: string
  isCompleted: boolean
  todoListId: number
}

export type ChangeEntityType = 1 | 2
export type ChangeOperation = 1 | 2 | 3

export interface ChangeNotification {
  eventId: number
  entityType: ChangeEntityType
  entityId: number
  operation: ChangeOperation
  occurredAt: string
}

