import { useEffect, useMemo, useRef, useState } from 'react'
import { LayoutGroup } from 'motion/react'
import * as api from './api/client'
import type { TodoList, TodoListItem } from './api/types'
import {
  findParentListId,
  mergeItemsByList,
  mergeItemsForList,
  mergeLists,
} from './api/sync-merge'
import Header from './components/Header'
import ListsBoard from './components/ListsBoard'
import ActiveListPanel from './components/ActiveListPanel'
import UndoToast from './components/UndoToast'
import { useUndoToast } from './hooks/useUndoToast'
import { useTodoSyncHub } from './hooks/useTodoSyncHub'
import { useT } from './i18n/I18nContext'
import './App.css'

const OP_UPDATE = 2
const OP_DELETE = 3

function App() {
  const { t } = useT()
  const [lists, setLists] = useState<TodoList[]>([])
  const [itemsByList, setItemsByList] = useState<Record<number, TodoListItem[]>>({})
  const [selectedId, setSelectedId] = useState<number | null>(null)
  const [autoFocusListId, setAutoFocusListId] = useState<number | null>(null)
  const [loading, setLoading] = useState(true)
  const [bootError, setBootError] = useState<string | null>(null)
  const undo = useUndoToast()

  const pendingDeletedItemIds = useRef<Set<number>>(new Set())
  const pendingDeletedListIds = useRef<Set<number>>(new Set())
  const inFlightItemUpdateIds = useRef<Set<number>>(new Set())
  const inFlightListUpdateIds = useRef<Set<number>>(new Set())

  const itemsByListRef = useRef(itemsByList)
  const bootstrappedRef = useRef(false)
  itemsByListRef.current = itemsByList

  useEffect(() => {
    document.title = t('app.title')
  }, [t])

  useEffect(() => {
    let cancelled = false
    async function bootstrap() {
      try {
        const fetched = await api.getLists()
        if (cancelled) return
        const itemEntries = await Promise.all(
          fetched.map(async (list) => [list.id, await api.getItems(list.id)] as const),
        )
        if (cancelled) return
        const map: Record<number, TodoListItem[]> = {}
        for (const [id, items] of itemEntries) map[id] = items
        setLists(fetched)
        setItemsByList(map)
        setSelectedId(fetched[0]?.id ?? null)
        bootstrappedRef.current = true
      } catch (e) {
        if (!cancelled) setBootError((e as Error).message)
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    bootstrap()
    return () => {
      cancelled = true
    }
  }, [])

  async function handleAddList(name: string) {
    const created = await api.createList(name)
    setLists((prev) => [...prev, created])
    setItemsByList((prev) => ({ ...prev, [created.id]: [] }))
    setSelectedId(created.id)
    setAutoFocusListId(created.id)
  }

import { useEffect, useRef, useState } from 'react'
import { HubConnectionState } from '@microsoft/signalr'
import { createHubConnection } from '../api/hub'
import type { ChangeNotification, ChangeOperation } from '../api/types'

export type ConnectionState =
  | 'connecting'
  | 'connected'
  | 'reconnecting'
  | 'disconnected'

export interface TodoSyncCallbacks {
  onListChanged: (entityId: number, op: ChangeOperation) => void | Promise<void>
  onItemChanged: (entityId: number, op: ChangeOperation) => void | Promise<void>
  onResync: () => void | Promise<void>
}

const DEDUPE_WINDOW_MS = 60_000
const DEDUPE_MAX = 500

export function useTodoSyncHub(cb: TodoSyncCallbacks): ConnectionState {
  const cbRef = useRef(cb)
  cbRef.current = cb

  const [state, setState] = useState<ConnectionState>('connecting')

  useEffect(() => {
    const connection = createHubConnection()
    const seen = new Map<number, number>()
    let disposed = false

    const isDuplicate = (n: ChangeNotification): boolean => {
      const now = Date.now()
      for (const [id, ts] of seen) {
        if (now - ts > DEDUPE_WINDOW_MS) seen.delete(id)
      }
      if (seen.has(n.eventId)) return true
      seen.set(n.eventId, now)
      if (seen.size > DEDUPE_MAX) {
        const oldest = seen.keys().next().value
        if (oldest !== undefined) seen.delete(oldest)
      }
      return false
    }

    connection.on('TodoListChanged', (n: ChangeNotification) => {
      if (isDuplicate(n)) return
      void cbRef.current.onListChanged(n.entityId, n.operation)
    })
    connection.on('TodoListItemChanged', (n: ChangeNotification) => {
      if (isDuplicate(n)) return
      void cbRef.current.onItemChanged(n.entityId, n.operation)
    })

    connection.onreconnecting(() => {
      if (!disposed) setState('reconnecting')
    })
    connection.onreconnected(() => {
      if (disposed) return
      setState('connected')
      void cbRef.current.onResync()
    })
    connection.onclose(() => {
      if (!disposed) setState('disconnected')
    })

    connection
      .start()
      .then(() => {
        if (disposed) return
        setState('connected')
        void cbRef.current.onResync()
      })
      .catch((err) => {
        if (disposed) return
        console.error('[useTodoSyncHub] start failed', err)
        setState('disconnected')
      })

    return () => {
      disposed = true
      if (connection.state !== HubConnectionState.Disconnected) {
        connection.stop().catch(() => {})
      }
    }
  }, [])

  return state
}

