  letter-spacing: 0.02em;
}

.sync-help-swatch {
  display: inline-block;
  width: 10px;
  height: 10px;
  margin-top: 4px;
  border-radius: 50%;
  border: 1px solid var(--border);
}

.sync-help-swatch[data-tone='ok'] {
  background: var(--pastel-mint-bg);
